import{getTinyMCE}from"editor_tiny/loader";import*as Configuration from"./configuration";import{getSetup}from"./commands";const pluginName="tiny_justify/plugin";export const pluginMetadata={name:pluginName,version:"2026030309"};export default new Promise(async resolve=>{const[tinyMCE,setupCommands]=await Promise.all([getTinyMCE(),getSetup()]);tinyMCE.PluginManager.add(pluginName,editor=>{setupCommands(editor);return pluginMetadata});resolve([pluginName,Configuration])});